'use client'

import { useState } from 'react'
import Link from 'next/link'
import { useRouter } from 'next/navigation'
import { useForm } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import { z } from 'zod'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Package, Loader2, Eye, EyeOff, Check } from 'lucide-react'

const registerSchema = z.object({
  companyName: z.string().min(2, 'Le nom de l\'entreprise doit contenir au moins 2 caracteres'),
  fullName: z.string().min(2, 'Le nom complet doit contenir au moins 2 caracteres'),
  email: z.string().email('Email invalide'),
  phone: z.string().optional(),
  password: z.string().min(8, 'Le mot de passe doit contenir au moins 8 caracteres'),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: 'Les mots de passe ne correspondent pas',
  path: ['confirmPassword'],
})

type RegisterForm = z.infer<typeof registerSchema>

const benefits = [
  '30 jours d\'essai gratuit',
  'Aucune carte bancaire requise',
  'Configuration en 5 minutes',
  'Support inclus',
]

export default function RegisterPage() {
  const router = useRouter()
  const [isLoading, setIsLoading] = useState(false)
  const [showPassword, setShowPassword] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<RegisterForm>({
    resolver: zodResolver(registerSchema),
  })

  async function onSubmit(data: RegisterForm) {
    setIsLoading(true)
    setError(null)

    try {
      const response = await fetch('/api/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          companyName: data.companyName,
          fullName: data.fullName,
          email: data.email,
          phone: data.phone,
          password: data.password,
        }),
      })

      const result = await response.json()

      if (!response.ok) {
        setError(result.error || 'Une erreur est survenue')
        return
      }

      // Redirect to login with success message
      router.push('/login?registered=true')
    } catch {
      setError('Une erreur est survenue. Veuillez reessayer.')
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white">
      {/* Left side - Registration Form */}
      <div className="flex-1 flex flex-col justify-center items-center px-8 py-20 relative overflow-hidden">
        {/* Subtle background pattern */}
        <div className="absolute inset-0 bg-[radial-gradient(#e2e8f0_1px,transparent_1px)] [background-size:32px_32px] opacity-[0.4]" />

        <div className="w-full max-w-[540px] relative z-10 space-y-12">
          {/* Mobile Header */}
          <div className="md:hidden flex flex-col items-center mb-12">
            <div className="flex h-16 w-16 items-center justify-center rounded-3xl bg-slate-950 text-white shadow-2xl mb-6">
              <Package className="h-8 w-8" />
            </div>
            <h2 className="text-4xl font-black tracking-tighter">B-Stock</h2>
          </div>

          <div className="text-center md:text-left">
            <h1 className="text-5xl font-black text-slate-950 tracking-tighter mb-4">Créer un compte</h1>
            <p className="text-slate-500 text-lg font-medium leading-relaxed">
              Propulsez votre dépôt dans une nouvelle ère de gestion.
            </p>
          </div>

          <div className="bg-white">
            <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
              {error && (
                <div className="rounded-3xl bg-red-50 border border-red-100 p-6 animate-in fade-in slide-in-from-top-4">
                  <p className="text-sm font-bold text-red-600 leading-relaxed flex items-center gap-3">
                    <span className="flex h-6 w-6 items-center justify-center rounded-full bg-red-100 text-[10px]">!</span>
                    {error}
                  </p>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <Label htmlFor="companyName" className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 ml-4">Entreprise</Label>
                  <Input
                    id="companyName"
                    placeholder="Ets. Boissons"
                    className="h-16 px-8 rounded-[2rem] bg-slate-50 border-transparent focus:bg-white focus:ring-blue-500 focus:border-blue-500/20 text-base font-bold transition-all shadow-sm"
                    {...register('companyName')}
                    disabled={isLoading}
                  />
                  {errors.companyName && (
                    <p className="text-xs text-red-500 font-bold ml-4">{errors.companyName.message}</p>
                  )}
                </div>

                <div className="space-y-3">
                  <Label htmlFor="fullName" className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 ml-4">Gérant / Admin</Label>
                  <Input
                    id="fullName"
                    placeholder="Jean Kouassi"
                    className="h-16 px-8 rounded-[2rem] bg-slate-50 border-transparent focus:bg-white focus:ring-blue-500 focus:border-blue-500/20 text-base font-bold transition-all shadow-sm"
                    {...register('fullName')}
                    disabled={isLoading}
                  />
                  {errors.fullName && (
                    <p className="text-xs text-red-500 font-bold ml-4">{errors.fullName.message}</p>
                  )}
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <Label htmlFor="email" className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 ml-4">Email Pro</Label>
                  <Input
                    id="email"
                    type="email"
                    placeholder="droit@depot.com"
                    className="h-16 px-8 rounded-[2rem] bg-slate-50 border-transparent focus:bg-white focus:ring-blue-500 focus:border-blue-500/20 text-base font-bold transition-all shadow-sm"
                    {...register('email')}
                    disabled={isLoading}
                  />
                  {errors.email && (
                    <p className="text-xs text-red-500 font-bold ml-4">{errors.email.message}</p>
                  )}
                </div>

                <div className="space-y-3">
                  <Label htmlFor="phone" className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 ml-4">Téléphone</Label>
                  <Input
                    id="phone"
                    placeholder="+225 07..."
                    className="h-16 px-8 rounded-[2rem] bg-slate-50 border-transparent focus:bg-white focus:ring-blue-500 focus:border-blue-500/20 text-base font-bold transition-all shadow-sm"
                    {...register('phone')}
                    disabled={isLoading}
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-3">
                  <Label htmlFor="password" colonial-className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 ml-4">Mot de passe</Label>
                  <div className="relative">
                    <Input
                      id="password"
                      type={showPassword ? 'text' : 'password'}
                      placeholder="••••••••"
                      className="h-16 px-8 rounded-[2rem] bg-slate-50 border-transparent focus:bg-white focus:ring-blue-500 focus:border-blue-500/20 text-base font-bold transition-all shadow-sm"
                      {...register('password')}
                      disabled={isLoading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-6 top-1/2 -translate-y-1/2 p-2 text-slate-300"
                    >
                      {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                    </button>
                  </div>
                  {errors.password && (
                    <p className="text-xs text-red-500 font-bold ml-4">{errors.password.message}</p>
                  )}
                </div>

                <div className="space-y-3">
                  <Label htmlFor="confirmPassword" colonial-className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400 ml-4">Confirmation</Label>
                  <Input
                    id="confirmPassword"
                    type="password"
                    placeholder="••••••••"
                    className="h-16 px-8 rounded-[2rem] bg-slate-50 border-transparent focus:bg-white focus:ring-blue-500 focus:border-blue-500/20 text-base font-bold transition-all shadow-sm"
                    {...register('confirmPassword')}
                    disabled={isLoading}
                  />
                  {errors.confirmPassword && (
                    <p className="text-xs text-red-500 font-bold ml-4">{errors.confirmPassword.message}</p>
                  )}
                </div>
              </div>

              <Button
                type="submit"
                className="w-full h-16 rounded-[2rem] bg-blue-600 hover:bg-blue-700 text-white text-lg font-black shadow-2xl shadow-blue-500/30 transition-all hover:scale-[1.01] active:scale-[0.99] disabled:opacity-50 mt-4"
                disabled={isLoading}
              >
                {isLoading ? (
                  <Loader2 className="h-6 w-6 animate-spin" />
                ) : (
                  'Lancer mon dépôt sur B-Stock'
                )}
              </Button>
            </form>

            <div className="mt-10 text-center">
              <p className="text-slate-500 font-bold">
                Déjà utilisateur ?{' '}
                <Link href="/login" className="text-blue-600 font-black hover:underline decoration-2 underline-offset-8">
                  Se connecter maintenant
                </Link>
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Right side - Benefits Overlay */}
      <div className="hidden lg:flex md:w-[40%] bg-slate-950 flex-col justify-between p-16 text-white overflow-hidden relative">
        <div className="absolute inset-0 z-0 opacity-40">
          <div className="absolute top-[20%] right-[-10%] w-[70%] h-[70%] bg-blue-600 rounded-full blur-[140px]" />
          <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-blue-400 rounded-full blur-[100px]" />
        </div>

        <div className="relative z-10">
          <p className="text-[11px] font-black uppercase tracking-[0.4em] text-blue-400 mb-8">Propulsez votre business</p>
          <h2 className="text-[3.5rem] font-black leading-[1] tracking-tighter mb-12">
            Pourquoi passer à <span className="text-blue-400">B-Stock ?</span>
          </h2>

          <div className="space-y-10">
            {benefits.map((benefit, i) => (
              <div key={i} className="flex items-start gap-4 group">
                <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-blue-500/20 text-blue-400 border border-blue-500/30 group-hover:bg-blue-500 group-hover:text-white transition-colors duration-500">
                  <Check className="h-4 w-4" />
                </div>
                <span className="text-lg font-bold text-white/80 leading-tight">{benefit}</span>
              </div>
            ))}
          </div>
        </div>

        <div className="relative z-10 mt-auto">
          <div className="p-8 rounded-[2.5rem] bg-white/5 backdrop-blur-2xl border border-white/10">
            <p className="text-lg font-medium italic text-white/70 leading-relaxed mb-6">
              &ldquo;B-Stock a radicalement changé notre gestion quotidienne. Nos stocks sont précis à 100% et nos clients sont servis plus vite.&rdquo;
            </p>
            <div className="flex items-center gap-4">
              <div className="h-12 w-12 rounded-2xl bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center font-black text-xl">D</div>
              <div>
                <p className="font-black text-white leading-none">Moussa Diakité</p>
                <p className="text-xs font-bold text-white/40 uppercase tracking-widest mt-1">Dépôt Plateau</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}
